import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { toast } from 'react-toastify';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    toast.success('Logged out successfully!');
    navigate('/login');
  };

  return (
    <nav
      className="navbar navbar-expand-lg"
      style={{
        background: 'linear-gradient(90deg, rgba(30,60,114,0.95) 0%, rgba(42,82,152,0.95) 100%)',
        boxShadow: '0 4px 24px 0 rgba(30,60,114,0.10)',
        fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
        borderBottom: '2px solid #e0e0e0',
        zIndex: 1000
      }}
    >
      <div className="container-fluid d-flex justify-content-between align-items-center py-2">
        <div className="d-flex align-items-center">
          <a className="navbar-brand d-flex align-items-center fw-bold" href="/dashboard" style={{ fontSize: '1.7rem', color: '#fff', letterSpacing: 1 }}>
            <i className="fas fa-rss me-2 text-info" style={{ fontSize: '2rem' }}></i>
            RFID API Dashboard
          </a>
          <Link to="/rfid-integration" className="ms-4 nav-link fw-semibold text-white d-flex align-items-center" style={{ fontSize: '1.1rem', opacity: 0.92, transition: 'opacity 0.2s' }}>
            <i className="fas fa-plug me-2 text-success"></i>
            RFID Integration
          </Link>
        </div>
        <div className="d-flex align-items-center">
          {userInfo && (
            <div className="text-white me-3 d-flex align-items-center bg-dark bg-opacity-25 px-3 py-2 rounded-4 shadow-sm" style={{ fontWeight: 500 }}>
              <i className="fas fa-user-circle me-2 text-info" style={{ fontSize: '1.5rem' }}></i>
              <span className="me-3" style={{ fontSize: '1.1rem' }}>{userInfo.Username}</span>
              <span className="badge bg-warning text-dark px-3 py-2" style={{ fontSize: '1em', fontWeight: 600, letterSpacing: 1 }}>
                <i className="fas fa-building me-1"></i>
                {userInfo.ClientCode || 'Not Available'}
              </span>
            </div>
          )}
          <button
            className="btn fw-bold shadow-sm ms-2"
            style={{
              background: 'linear-gradient(90deg, #1e3c72 0%, #2a5298 100%)',
              color: '#fff',
              border: 'none',
              fontSize: '1.1rem',
              letterSpacing: 1,
              padding: '0.5rem 1.2rem',
              borderRadius: 8,
              transition: '0.2s',
              boxShadow: '0 2px 8px rgba(30,60,114,0.15)'
            }}
            onClick={handleLogout}
            onMouseOver={e => e.currentTarget.style.background = 'linear-gradient(90deg, #2a5298 0%, #1e3c72 100%)'}
            onMouseOut={e => e.currentTarget.style.background = 'linear-gradient(90deg, #1e3c72 0%, #2a5298 100%)'}
          >
            <i className="fas fa-sign-out-alt me-2"></i>
            Logout
          </button>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </nav>
  );
};

export default Header;
